
"use client";

import React, { useMemo, useState, useEffect } from 'react';
import { User, AppData, UploadedDoc } from '@/lib/types';
import { cn, fmt } from '@/lib/utils';
import { getGlobalAppData, getUsers, getAllApprovedCamps, getPendingCamps, saveUsers, addUserNotification } from '@/lib/store';
import { 
    DollarSign, 
    TrendingUp, 
    Users as UsersIcon, 
    CheckCircle, 
    Gem, 
    Hourglass, 
    Eye, 
    FileX, 
    CheckCircle2,
    Mountain, 
    Shield, 
    ClipboardList,
    Calendar
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { toast } from '@/hooks/use-toast';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";

interface AdminDashboardProps {
  currentUser: User;
  data: AppData;
  onNavigate: (page: string, params?: any) => void;
}

const StatCard = ({ icon: Icon, title, value, change, borderColor, textColor, bgColor, iconBgColor }) => (
    <div className={`bg-white p-5 rounded-xl shadow-sm border-t-4 ${borderColor}`}>
        <div className="flex justify-between items-start">
            <p className={`text-sm font-semibold ${textColor}`}>{title}</p>
            <div className={`p-2 rounded-full ${iconBgColor}`}>
                <Icon className={`w-6 h-6 ${textColor}`} />
            </div>
        </div>
        <p className={`text-3xl font-bold ${textColor} mt-2`}>{value}</p>
        <p className={`text-sm mt-1 ${textColor}`}>{change}</p>
    </div>
);

export default function AdminDashboard({ currentUser, data, onNavigate }: AdminDashboardProps) {
    const [allUsersState, setAllUsersState] = useState<Record<string, User>>({});
    const [refreshKey, setRefreshKey] = useState(0);

    useEffect(() => {
        const interval = setInterval(() => setRefreshKey(p => p + 1), 5000);
        return () => clearInterval(interval);
    }, []);

    const { 
        totalRevenue, 
        totalBookings, 
        pendingBookings, 
        totalCamps, 
        pendingApprovals, 
        organizerReviews, 
        totalUsers 
    } = useMemo(() => {
        const users = getUsers();
        const globalData = getGlobalAppData();
        const allCamps = getAllApprovedCamps();

        return {
            totalRevenue: globalData.allBookings.reduce((sum, b) => sum + (b.status === 'Confirmed' ? b.amount : 0), 0),
            totalBookings: globalData.allBookings.length,
            pendingBookings: globalData.allBookings.filter(b => b.status === 'Pending').length,
            totalCamps: allCamps.length,
            pendingApprovals: Object.values(users).filter(u => u.role === 'organizer' && !u.isApproved && !u.isRejected).length,
            organizerReviews: 1, // Placeholder
            totalUsers: Object.keys(users).length,
        };
    }, [refreshKey]);

    const statCards = [
        { icon: DollarSign, title: 'TOTAL REVENUE', value: `₹${fmt(totalRevenue)}`, change: '↑ +12.5%', borderColor: 'border-green-400', textColor: 'text-green-600', iconBgColor: 'bg-green-100' },
        { icon: ClipboardList, title: 'TOTAL BOOKINGS', value: totalBookings, change: '↑ +8.2%', borderColor: 'border-orange-400', textColor: 'text-orange-600', iconBgColor: 'bg-orange-100' },
        { icon: Hourglass, title: 'PENDING BOOKINGS', value: pendingBookings, change: '↑ Requires action', borderColor: 'border-yellow-400', textColor: 'text-yellow-600', iconBgColor: 'bg-yellow-100' },
        { icon: Mountain, title: 'TOTAL CAMPS', value: totalCamps, change: '↑ Approved', borderColor: 'border-teal-400', textColor: 'text-teal-600', iconBgColor: 'bg-teal-100' },
        { icon: Hourglass, title: 'PENDING APPROVAL', value: pendingApprovals, change: '↑ Needs Review', borderColor: 'border-amber-400', textColor: 'text-amber-600', iconBgColor: 'bg-amber-100' },
        { icon: Shield, title: 'ORGANIZER REVIEWS', value: organizerReviews, change: '↑ Pending', borderColor: 'border-purple-400', textColor: 'text-purple-600', iconBgColor: 'bg-purple-100' },
    ];

    return (
        <div className="bg-[#f0f2f5] p-8 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 xl:grid-cols-7 gap-6">
                {statCards.map((card, index) => <div className="col-span-1" key={index}><StatCard {...card} /></div>)}
                <div className="col-span-1">
                    <StatCard 
                        icon={UsersIcon} 
                        title="TOTAL USERS" 
                        value={totalUsers} 
                        change="↑ Active" 
                        borderColor="border-indigo-400" 
                        textColor="text-indigo-600" 
                        iconBgColor="bg-indigo-100" 
                    />
                </div>
            </div>
        </div>
    );
}
